args.sparql:
SELECT ?games WHERE {
  wd:Q504309 p:P1344 [
    ps:P1344 ?series;
    pq:P1350 ?games
  ].
  ?series wdt:P1110 ?attendance.
  FILTER(isNumeric(?attendance) && isNumeric(?games))
} ORDER BY ( ?attendance / ?games ) LIMIT 3

